const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // Explore interactive elements
  const elements = await page.evaluate(() => {
    const all = document.querySelectorAll('button, a, input, [role="button"], [role="tab"], .menu-item, .nav-item, li, [class*="menu"], [class*="nav"], [class*="search"], [class*="customer"]');
    const items = [];
    all.forEach(el => {
      const rect = el.getBoundingClientRect();
      if (rect.width > 0 && rect.height > 0) {
        items.push({
          tag: el.tagName,
          text: (el.textContent || '').trim().substring(0, 50),
          class: (el.className || '').substring(0, 60),
          id: el.id,
          href: el.href || '',
          visible: rect.top < window.innerHeight && rect.left < window.innerWidth
        });
      }
    });
    return items;
  });

  console.log('=== 页面元素 ===');
  elements.forEach(el => {
    if (el.text || el.id) {
      console.log(`[${el.tag}] "${el.text}" class="${el.class}" id="${el.id}" ${el.href ? 'href='+el.href : ''}`);
    }
  });

  // Check frame structure
  const frames = page.frames();
  console.log('\n=== Frames ===');
  frames.forEach((f, i) => {
    console.log(`Frame ${i}: ${f.url().substring(0, 150)}`);
  });

  // Look for search input or customer search
  const inputs = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('input')).map(i => ({
      placeholder: i.placeholder,
      type: i.type,
      id: i.id,
      className: (i.className || '').substring(0, 50)
    }));
  });
  console.log('\n=== Inputs ===');
  inputs.forEach(i => console.log(JSON.stringify(i)));

})().catch(err => {
  console.error('Error:', err);
  process.exit(1);
});

