const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  if (!page) { console.log('no page'); return; }

  // Take screenshot
  await page.screenshot({ path: 'okki_full.png', fullPage: true });
  console.log('screenshot saved');

  // Dump all frames
  const frames = page.frames();
  console.log('=== All Frames ===');
  for (const f of frames) {
    console.log('Frame:', f.url().substring(0, 200));
    try {
      const title = await f.title();
      console.log('  Title:', title.substring(0, 100));
      const html = await f.evaluate(() => document.body ? document.body.innerHTML.substring(0, 500) : 'no body');
      console.log('  Body start:', html.replace(/</g, '&lt;').substring(0, 300));
    } catch(e) {
      console.log('  Error:', e.message.substring(0, 100));
    }
  }

  // Look for iframes specifically
  const iframes = await page.evaluate(() => {
    const frames = document.querySelectorAll('iframe');
    return Array.from(frames).map(f => ({
      src: f.src,
      id: f.id,
      cls: typeof f.className === 'string' ? f.className : '',
      visible: f.getBoundingClientRect().width > 0,
      w: f.getBoundingClientRect().width,
      h: f.getBoundingClientRect().height
    }));
  });
  console.log('=== iframes in main page ===');
  iframes.forEach(f => console.log(JSON.stringify(f)));

  // Also check which tab is active
  const tabState = await page.evaluate(() => {
    const tabs = document.querySelectorAll('.okki-tabs-tabpane');
    return Array.from(tabs).map(t => ({
      id: t.id,
      class: typeof t.className === 'string' ? t.className : '',
      visible: t.getBoundingClientRect().width > 0
    }));
  });
  console.log('=== Tab panes ===');
  tabState.forEach(t => console.log(JSON.stringify(t)));

  // Get main TM panel content
  const tmPanel = await page.evaluate(() => {
    const panel = document.querySelector('#rc-tabs-3-panel-TalkHubTm');
    if (!panel) return 'no panel';
    return {
      html: panel.innerHTML.substring(0, 1000).replace(/</g, '&lt;'),
      visible: panel.getBoundingClientRect().width > 0
    };
  });
  console.log('=== TM Panel ===');
  console.log(tmPanel);

  // Look for the search input in more detail
  const searchInput = await page.evaluate(() => {
    const input = document.querySelector('.search-input');
    if (!input) return 'no search-input found';
    // find parent
    let parent = input.parentElement;
    let chain = '';
    for (let i = 0; i < 5 && parent; i++) {
      chain += (typeof parent.className === 'string' ? parent.className : '?') + ' > ';
      parent = parent.parentElement;
    }
    return {
      placeholder: input.placeholder,
      parentChain: chain,
      parentHTML: input.parentElement ? input.parentElement.innerHTML.substring(0, 500).replace(/</g, '&lt;') : ''
    };
  });
  console.log('=== Search Input ===');
  console.log(JSON.stringify(searchInput, null, 2));

  await browser.close();
})().catch(e => { console.error(e.message); });
