const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));

  // Find the talk iframe frame by URL pattern
  const talkFrame = page.frames().find(f =>
    f.url().includes('onetalk.alibaba') || f.url().includes('weblitePWA')
  );

  if (!talkFrame) {
    console.log('Talk iframe not found. Dumping all frame URLs:');
    page.frames().forEach((f, i) => console.log(`Frame ${i}: ${f.url().substring(0, 200)}`));
    await browser.close();
    process.exit(1);
  }

  console.log('=== Talk Iframe URL ===');
  console.log(talkFrame.url());

  // 1. Explore conversation list
  const listStructure = await talkFrame.evaluate(() => {
    const items = [];

    // Find conversation list container
    const containers = document.querySelectorAll(
      'div[class*="list"], div[class*="conversation"], div[class*="session"], div[class*="chat"], div[class*="msg"], div[class*="contact"], ul, [role="listbox"], [role="list"]'
    );
    containers.forEach(el => {
      const cls = typeof el.className === 'string' ? el.className : '';
      const text = (el.textContent || '').trim().substring(0, 100);
      const rect = el.getBoundingClientRect();
      items.push({
        tag: el.tagName,
        class: cls.substring(0, 80),
        text,
        w: Math.round(rect.width),
        h: Math.round(rect.height),
        childCount: el.children.length
      });
    });
    return items;
  });

  console.log(`\n=== Containers in talk iframe (${listStructure.length}) ===`);
  listStructure.forEach(el => {
    if (el.w > 50) {
      console.log(`[${el.tag}] w=${el.w} h=${el.h} kids=${el.childCount} class=${el.class}`);
      console.log(`  text: "${el.text.substring(0, 120)}"`);
    }
  });

  // 2. Find conversation items specifically
  const convItems = await talkFrame.evaluate(() => {
    const items = [];
    // Try various conversation item selectors
    const all = document.querySelectorAll('div[class*="conversation"], div[class*="session"], div[class*="chat-item"], li[class*="chat"], li[class*="session"], [class*="contact-item"], [class*="list-item"]');
    all.forEach((el, idx) => {
      try {
        const cls = typeof el.className === 'string' ? el.className : '';
        const text = (el.textContent || '').trim().substring(0, 80);
        const rect = el.getBoundingClientRect();
        if (text && rect.width > 0) {
          items.push({
            idx,
            tag: el.tagName,
            class: cls.substring(0, 60),
            text,
            w: Math.round(rect.width),
            h: Math.round(rect.height),
            html: el.innerHTML.substring(0, 300).replace(/</g, '&lt;')
          });
        }
      } catch(e) {}
    });
    return items;
  });

  console.log(`\n=== Conversation items (${convItems.length}) ===`);
  convItems.forEach(el => {
    console.log(`[${el.idx}] ${el.tag} "${el.text}" (${el.w}x${el.h})`);
    console.log(`  class=${el.class}`);
    console.log(`  html=${el.html}`);
    console.log('');
  });

  // 3. Get all clickable items in the left panel
  const clickables = await talkFrame.evaluate(() => {
    const items = [];
    document.querySelectorAll('[class*="left"], [class*="sidebar"], [class*="panel"]').forEach(el => {
      const cls = typeof el.className === 'string' ? el.className : '';
      const rect = el.getBoundingClientRect();
      if (rect.width > 100 && rect.height > 100) {
        items.push({ tag: el.tagName, class: cls.substring(0, 80), w: Math.round(rect.width), h: Math.round(rect.height) });
      }
    });
    return items;
  });
  console.log(`\n=== Large panels ===`);
  clickables.forEach(el => console.log(`${el.tag} class=${el.class} (${el.w}x${el.h})`));

  // 4. Check for message/conversation search input inside iframe
  const inputs = await talkFrame.evaluate(() => {
    return Array.from(document.querySelectorAll('input, [contenteditable]')).map(i => {
      const rect = i.getBoundingClientRect();
      return {
        placeholder: i.placeholder || '',
        id: i.id,
        class: (typeof i.className === 'string' ? i.className : '').substring(0, 50),
        visible: rect.width > 0,
        w: Math.round(rect.width)
      };
    }).filter(i => i.visible);
  });
  console.log(`\n=== Inputs in talk iframe ===`);
  inputs.forEach(i => console.log(JSON.stringify(i)));

  await browser.close();
})().catch(err => {
  console.error('Error:', err.message);
  process.exit(1);
});

