const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));

  // 1. Try to access each frame directly
  const frames = page.frames();
  console.log(`=== ${frames.length} frames ===`);
  for (let i = 0; i < frames.length; i++) {
    const f = frames[i];
    console.log(`\n--- Frame ${i}: url="${f.url().substring(0, 200)}" ---`);
    try {
      const title = await f.title();
      console.log(`  title="${title}"`);
      const text = await f.evaluate(() => document.body?.innerText?.substring(0, 2000) || 'no body');
      console.log(`  text:\n${text.substring(0, 1000)}`);
    } catch (e) {
      console.log(`  ERROR: ${e.message.substring(0, 150)}`);
    }
  }

  // 2. Try to access iframe via page context (contentWindow)
  console.log('\n=== Try accessing iframe via contentWindow ===');
  const iframeAccess = await page.evaluate(() => {
    const iframe = document.getElementById('talk-tm-iframe');
    if (!iframe) return 'no iframe element found';
    try {
      const doc = iframe.contentDocument || iframe.contentWindow?.document;
      if (doc) {
        return {
          title: doc.title,
          url: doc.URL,
          bodyLen: doc.body?.innerText?.length || 0,
          bodyStart: doc.body?.innerText?.substring(0, 500) || ''
        };
      }
      return 'contentDocument not accessible (cross-origin)';
    } catch(e) {
      return 'Error: ' + e.message;
    }
  });
  console.log(JSON.stringify(iframeAccess, null, 2));

  // 3. Enable network monitoring to find API calls from the iframe
  console.log('\n=== Monitoring network requests... ===');
  const apiCalls = [];
  page.on('request', req => {
    const url = req.url();
    if (url.includes('alibaba') || url.includes('xiaoman') || url.includes('api') || url.includes('graphql')) {
      if (url.includes('/api/') || url.includes('message') || url.includes('conversation') || url.includes('chat') || url.includes('session')) {
        apiCalls.push({
          url: url.substring(0, 300),
          method: req.method(),
          type: req.resourceType()
        });
      }
    }
  });

  // Wait for a few seconds to capture API traffic
  await new Promise(r => setTimeout(r, 5000));
  console.log(`\n=== Captured ${apiCalls.length} relevant API calls ===`);
  apiCalls.forEach(c => console.log(`[${c.method}] ${c.type} ${c.url}`));

  // 4. Also check if the iframe has loaded by checking what's in the main page
  const iframeInfo = await page.evaluate(() => {
    const iframe = document.getElementById('talk-tm-iframe');
    if (!iframe) return 'no iframe';
    const style = window.getComputedStyle(iframe);
    return {
      src: iframe.src,
      visible: style.display !== 'none' && style.visibility !== 'hidden',
      w: iframe.offsetWidth,
      h: iframe.offsetHeight
    };
  });
  console.log(`\n=== Iframe info ===`);
  console.log(JSON.stringify(iframeInfo));

  await browser.close();
})().catch(err => {
  console.error('Fatal:', err.message);
});

