    console.log('\n🔍 切换到"待回复"筛选...');
    await clickFilterTab(talkFrame, '待回复');
    const pendingList = await getConversationList(talkFrame);
    console.log(`   待回复会话: ${pendingList.length} 个`);

    // 4. 遍历所有会话，获取详细消息
    const allData = [];
    const total = conversations.length;

    for (let i = 0; i < total; i++) {
      const conv = conversations[i];
      console.log(`\n💬 [${i + 1}/${total}] ${conv.name}`);

      const clickedName = await clickConversation(talkFrame, i);
      if (!clickedName) {
        console.log(`   ⚠️ 无法点击`);
        continue;
      }

      const messages = await getCurrentMessages(talkFrame);
      console.log(`   ${messages.length} 条消息`);

      allData.push({
        name: conv.name,
        status: conv.isUnread ? 'unread' : conv.isRead ? 'read' : 'other',
        lastTime: conv.time,
        lastMessageSnippet: conv.rawText.substring(0, 200),
        messages: messages.map(m => ({
          type: m.type,
          side: m.side,
          content: m.content,
          translated: m.translated,
        })),
      });
    }

    // 5. 保存
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
    const outputPath = join(DATA_DIR, `数据快照_${timestamp}.json`);
    writeFileSync(outputPath, JSON.stringify(allData, null, 2), 'utf-8');
    console.log(`\n✅ 数据已保存: ${outputPath}`);
    console.log(`   共 ${allData.length} 个会话`);

    return allData;
  } finally {
    await browser.close();
  }
}

// 运行
scrapeAll().catch(err => {
  console.error('❌ 抓取失败:', err.message);
  process.exit(1);
