/**
 * 探查：TM聊天中的文件和附件类型
 */
const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  const talkFrame = page.frames()[1];

  // 获取第一个会话的消息，分析所有元素类型
  const analysis = await talkFrame.evaluate(() => {
    const results = [];
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(w => {
      const items = [];
      // All possible child types
      w.querySelectorAll('*').forEach(el => {
        const tag = el.tagName.toLowerCase();
        const cls = typeof el.className === 'string' ? el.className : '';
        const text = (el.textContent || '').trim().substring(0, 40);
        const rect = el.getBoundingClientRect();

        // Only report meaningful elements
        if (rect.width > 5 && rect.height > 5) {
          if (tag === 'img' || tag === 'a' || cls.includes('file') || cls.includes('attach') ||
              cls.includes('download') || cls.includes('card') || cls.includes('product') ||
              cls.includes('image') || cls.includes('pdf') || tag === 'video' || tag === 'audio') {
            items.push({
              tag,
              class: cls.substring(0, 50),
              text,
              href: el.href || '',
              src: el.src || '',
              w: Math.round(rect.width),
              h: Math.round(rect.height),
            });
          }
        }
      });
      if (items.length > 0) results.push(...items);
    });
    return results;
  });

  console.log('=== 消息中的元素类型分析 ===');
  const types = {};
  analysis.forEach(item => {
    const key = `${item.tag} | ${item.class}`;
    if (!types[key]) types[key] = { tag: item.tag, class: item.class, count: 0, samples: [] };
    types[key].count++;
    if (types[key].samples.length < 3) {
      types[key].samples.push({ text: item.text, href: item.href?.substring(0, 100), src: item.src?.substring(0, 100) });
    }
  });

  Object.entries(types).forEach(([key, info]) => {
    console.log(`\n[${info.tag}] class="${info.class}" × ${info.count}`);
    info.samples.forEach(s => console.log(`  text="${s.text}" ${s.href ? 'href='+s.href : ''} ${s.src ? 'src='+s.src : ''}`));
  });

  // 专门检查: 有没有文件下载/附件链接
  console.log('\n=== 文件类元素检查 ===');
  const fileElements = await talkFrame.evaluate(() => {
    const files = [];
    // 所有<a>标签
    document.querySelectorAll('a[href*="download"], a[href*="file"], a[href*="clouddisk"], a[href*="aliyun"], [class*="download"], [class*="file"]').forEach(el => {
      files.push({
        tag: el.tagName,
        text: (el.textContent || '').trim().substring(0, 60),
        href: el.href?.substring(0, 200) || '',
        class: (typeof el.className === 'string' ? el.className : '').substring(0, 60),
      });
    });
    return files;
  });
  console.log(`找到 ${fileElements.length} 个文件元素`);
  fileElements.forEach(f => console.log(`  "${f.text}" href=${f.href} class=${f.class}`));

  // 消息内容分类统计
  const contentTypeAnalysis = await talkFrame.evaluate(() => {
    const counts = { text: 0, card: 0, image: 0, file: 0, translate: 0, security: 0, other: 0 };
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(w => {
      if (w.querySelector('.session-rich-content.text')) counts.text++;
      else if (w.querySelector('.session-rich-content.card')) counts.card++;
      else if (w.querySelector('.session-translate')) counts.translate++;
      else if (w.querySelector('.session-security')) counts.security++;
      else if (w.querySelector('img[src*="alicdn"]')) counts.image++;
      else counts.other++;
    });
    return counts;
  });
  console.log('\n=== 消息内容类型分布 ===');
  Object.entries(contentTypeAnalysis).forEach(([k, v]) => console.log(`  ${k}: ${v}`));

  await browser.close();
})().catch(err => { console.error(err.message); });

