      // Direct children class names
      w.querySelectorAll(':scope > *').forEach(c => {
        const cls = typeof c.className === 'string' ? c.className : '';
        const key = `CHILD: ${cls.substring(0, 80)}`;
        msgTypes[key] = (msgTypes[key] || 0) + 1;

        // Check for special elements
        c.querySelectorAll('img, a, video, audio, iframe, embed, object').forEach(el => {
          const tag = el.tagName.toLowerCase();
