    const items = [];
    document.querySelectorAll('a[href*="clouddisk"], a[href*="file"], a[href*="download"], a[href*="aliyun"], [class*="file"], [class*="attach"], [class*="down"]').forEach(el => {
      items.push({
        text: (el.textContent || '').trim().substring(0, 60),
        href: (el.href || '').substring(0, 150),
        class: (typeof el.className === 'string' ? el.className : '').substring(0, 50),
      });
    });
    return items;
  });
  console.log(`\n=== 云盘/文件链接: ${cloudFiles.length} 个 ===`);
  cloudFiles.forEach(f => console.log(`  "${f.text}" ${f.href} [${f.class}]`));

  await browser.close();
})().catch(err => { console.error(err.message); });

