      if (s.href) console.log(`  href=${s.href}`);
      if (s.src) console.log(`  src=${s.src}`);
    });
  });

  // 统计消息结构
  const structure = await tf.evaluate(() => {
    const types = {};
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(w => {
      // What's the top-level structure?
      const directClasses = [];
      w.querySelectorAll(':scope > *').forEach(c => {
        const cls = typeof c.className === 'string' ? c.className : '';
        directClasses.push(cls.substring(0, 60));
      });
      directClasses.forEach(c => { types[c] = (types[c] || 0) + 1; });
    });
    return types;
  });
  console.log('\n=== 消息顶层结构分布 ===');
  Object.entries(structure).forEach(([k, v]) => console.log(`  "${k.substring(0, 80)}": ${v}`));

  await browser.close();
})().catch(err => { console.error(err.message); });

