  const hasAttachments = await page.evaluate(() => {
    return {
      attachLinks: document.querySelectorAll('a[href*="attach"], a[href*="file"], [class*="attach"], [class*="file"], i[class*="attach"]').length,
      downloadLinks: document.querySelectorAll('a[href*="download"], [class*="download"]').length,
