/**
 * 探查：TM聊天中的文件和附件类型
 */
const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  let page = ctx.pages().find(p => p.url().includes('xiaoman'));

  // 确保在沟通/TM页面
  if (!page.url().includes('talk')) {
    await page.evaluate(() => {
      const items = document.querySelectorAll('.fixed-menu-item, a');
      for (const el of items) {
        if (el.textContent?.trim() === '沟通') { el.click(); return; }
      }
    });
    await new Promise(r => setTimeout(r, 4000));
    // Re-acquire page reference
    page = ctx.pages().find(p => p.url().includes('xiaoman'));
  }

  const tf = page.frames()[1];
  if (!tf) { console.log('no talk frame'); return; }

  // 点击第一个有真实消息的会话
  await tf.evaluate(() => {
    const containers = document.querySelectorAll('.contact-item-container');
    for (const c of containers) {
      const text = c.textContent || '';
      if (!text.includes('Assistant') && !text.includes('自动接待') && !text.includes('Eva')) {
        c.click();
        return;
      }
    }
  });
  await new Promise(r => setTimeout(r, 2500));

  // 分析消息结构
  const structure = await tf.evaluate(() => {
    const msgTypes = {};
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(w => {
      // Top-level class
      const topCls = typeof w.className === 'string' ? w.className : '';
      msgTypes[topCls] = (msgTypes[topCls] || 0) + 1;

      // Direct children class names
      w.querySelectorAll(':scope > *').forEach(c => {
        const cls = typeof c.className === 'string' ? c.className : '';
        const key = `CHILD: ${cls.substring(0, 80)}`;
        msgTypes[key] = (msgTypes[key] || 0) + 1;

        // Check for special elements
        c.querySelectorAll('img, a, video, audio, iframe, embed, object').forEach(el => {
          const tag = el.tagName.toLowerCase();
          const extras = [];
          if (el.src) extras.push(`src=${el.src.substring(0, 80)}`);
          if (el.href) extras.push(`href=${el.href.substring(0, 80)}`);
          const key2 = `${tag}: ${extras.join(' ')}`;
          msgTypes[key2] = (msgTypes[key2] || 0) + 1;
        });
      });
    });
    return msgTypes;
  });

  console.log('=== 消息结构和文件类型 ===');
  Object.entries(structure).sort((a, b) => b[1] - a[1]).forEach(([k, v]) => {
    console.log(`  ${v}x ${k.substring(0, 150)}`);
  });

  // 检查云盘文件
  const cloudFiles = await tf.evaluate(() => {
    const items = [];
    document.querySelectorAll('a[href*="clouddisk"], a[href*="file"], a[href*="download"], a[href*="aliyun"], [class*="file"], [class*="attach"], [class*="down"]').forEach(el => {
      items.push({
        text: (el.textContent || '').trim().substring(0, 60),
        href: (el.href || '').substring(0, 150),
        class: (typeof el.className === 'string' ? el.className : '').substring(0, 50),
      });
    });
    return items;
  });
  console.log(`\n=== 云盘/文件链接: ${cloudFiles.length} 个 ===`);
  cloudFiles.forEach(f => console.log(`  "${f.text}" ${f.href} [${f.class}]`));

  await browser.close();
})().catch(err => { console.error(err.message); });

/**
 * 探查：客户列表完整分页 + 对话历史滚动 + 图片URL
 */
const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  if (!page) { console.log('no page'); return; }

  // 已经在客户页面了，检查分页结构
  console.log('=== 客户列表分页结构 ===');
  const pageInfo = await page.evaluate(() => {
    // 分页控件
    const pagination = document.querySelector('.okki-pagination, [class*="pagination"]');
    if (!pagination) return 'no pagination found';
    return {
      html: pagination.innerHTML.replace(/</g, '&lt;').substring(0, 2000),
      text: pagination.textContent?.trim().substring(0, 200),
    };
  });
  console.log(JSON.stringify(pageInfo, null, 2));

  // 检查客户列表行结构
  const rowInfo = await page.evaluate(() => {
    const rows = document.querySelectorAll('table tr, [class*="row"], [class*="list-item"], .okki-table-row');
    return Array.from(rows).slice(0, 5).map((row, i) => ({
      idx: i,
      text: (row.textContent || '').trim().substring(0, 200),
      class: typeof row.className === 'string' ? row.className.substring(0, 80) : '',
      html: row.innerHTML.replace(/</g, '&lt;').substring(0, 500),
      cells: Array.from(row.querySelectorAll('td, th, [class*="cell"]')).map(c => ({
        text: (c.textContent || '').trim().substring(0, 60),
        class: (typeof c.className === 'string' ? c.className : '').substring(0, 40),
      })),
    }));
  });
  console.log('\n=== 表格行结构 ===');
  rowInfo.forEach(r => {
    console.log(`\nRow ${r.idx}: class=${r.class}`);
    r.cells.forEach((c, i) => console.log(`  Cell ${i}: "${c.text}" (${c.class})`));
  });

  // 尝试点击第2页
  console.log('\n=== 分页导航测试 ===');
  const testPage = await page.evaluate(() => {
    // 找页码按钮
    const links = document.querySelectorAll('.okki-pagination li, .okki-pagination a, .okki-pagination button, [class*="pagination"] a, a[class*="page"]');
    for (const el of links) {
      if (el.textContent?.trim() === '2') {
        el.click();
        return `clicked page 2: ${el.outerHTML?.substring(0, 200)}`;
      }
    }
    // Alternative: find the page input or next button
    return 'page 2 not found';
  });
  console.log(testPage);
  await new Promise(r => setTimeout(r, 2000));

  // 检查URL是否变了
  console.log('当前URL:', page.url().substring(0, 300));

  // 回到TM页面，检查消息区的"加载更多"按钮
  console.log('\n=== TM消息区加载更多 ===');
  // 先回到TM页面
  await page.evaluate(() => {
    const items = document.querySelectorAll('.fixed-menu-item, a');
    for (const el of items) {
      if (el.textContent?.trim() === '沟通') {
        el.click();
        return;
      }
    }
  });
  await new Promise(r => setTimeout(r, 3000));

  const talkFrame = page.frames()[1];
  if (!talkFrame) { console.log('no talk frame'); return; }

  // 检查消息区顶部是否有加载更多按钮
  const loadMore = await talkFrame.evaluate(() => {
    // 滚动消息区到顶
    const msgFlow = document.querySelector('.message-flow-container.messenger');
    if (msgFlow) msgFlow.scrollTop = 0;
    // 等待是否有加载触发
    return new Promise(resolve => {
      setTimeout(() => {
        // Check for load more indicators
        const loadMoreBtns = document.querySelectorAll('button, a, [class*="load"], [class*="more"], [class*="history"]');
        const found = [];
        loadMoreBtns.forEach(b => {
          const text = b.textContent?.trim() || '';
          if (text.toLowerCase().includes('load') || text.toLowerCase().includes('more') || text.includes('历史') || text.includes('加载') || text.includes('更多')) {
            found.push(text);
          }
        });
        // Check number of messages again
        const msgCount = document.querySelectorAll('.message-item-wrapper.messenger').length;
        resolve({ found, msgCount });
      }, 3000);
    });
  });
  console.log('加载更多按钮:', JSON.stringify(loadMore));

  // 检查消息区是否可无限滚动
  const scrollTest = await talkFrame.evaluate(() => {
    const msgFlow = document.querySelector('.message-flow-container.messenger');
    if (!msgFlow) return { error: 'no message flow' };
    const before = msgFlow.scrollHeight;
    // Scroll to very top
    msgFlow.scrollTop = -100; // Try negative to force trigger
    return new Promise(resolve => {
      setTimeout(() => {
        const after = msgFlow.scrollHeight;
        resolve({ before, after, diff: after - before, scrollTop: msgFlow.scrollTop });
      }, 3000);
    });
  });
  console.log('消息区滚动测试:', JSON.stringify(scrollTest));

  // 获取可点击的图片查看其完整src
  const imageUrls = await talkFrame.evaluate(() => {
    const urls = new Set();
    document.querySelectorAll('.message-item-wrapper.messenger img').forEach(img => {
      if (img.src) urls.add(img.src.substring(0, 200));
    });
    return Array.from(urls).slice(0, 10);
  });
  console.log('\n图片URL样例:');
  imageUrls.forEach((url, i) => console.log(`  [${i}] ${url}`));

  await browser.close();
})().catch(err => { console.error(err.message); });

/**
 * 探查：客户全量列表 + 会话消息滚动 + 图片处理
 */
const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  if (!page) { console.log('no page'); return; }

  console.log('=== 当前URL ===');
  console.log(page.url());

  // 1. TM聊天 — 滚动加载更多会话，看能加载多少
  const talkFrame = page.frames()[1];
  if (!talkFrame) { console.log('no talk frame'); return; }

  console.log('\n=== TM 会话列表滚动测试 ===');
  // 先获取当前可见数
  let before = await talkFrame.evaluate(() => document.querySelectorAll('.contact-item-container').length);
  console.log(`滚动前: ${before} 个会话`);

  // 多次滚动到底部
  for (let i = 0; i < 10; i++) {
    await talkFrame.evaluate(() => {
      const c = document.querySelector('.seller-conversation-list') || document.querySelector('.conversation-list-content');
      if (c) c.scrollTop = c.scrollHeight;
    });
    await new Promise(r => setTimeout(r, 800));
    const after = await talkFrame.evaluate(() => document.querySelectorAll('.contact-item-container').length);
    if (after === before) break; // no more loaded
    console.log(`滚动 ${i + 1}: ${before} → ${after}`);
    before = after;
  }
  console.log(`最终: ${before} 个会话`);

  // 2. 检查一个消息区能滚动加载多少历史消息
  console.log('\n=== 消息历史滚动测试 ===');
  // 点击第一个会话
  await talkFrame.evaluate(() => {
    const first = document.querySelector('.contact-item-container');
    if (first) first.click();
  });
  await new Promise(r => setTimeout(r, 2000));

  // 先看当前可见消息数
  let msgBefore = await talkFrame.evaluate(() => document.querySelectorAll('.message-item-wrapper.messenger').length);
  console.log(`滚动消息前: ${msgBefore} 条可见`);

  // 滚动消息区顶部加载历史
  for (let i = 0; i < 8; i++) {
    await talkFrame.evaluate(() => {
      const c = document.querySelector('.message-flow-container.messenger');
      if (c) c.scrollTop = 0; // scroll to top to trigger history loading
    });
    await new Promise(r => setTimeout(r, 1500));
    const msgAfter = await talkFrame.evaluate(() => document.querySelectorAll('.message-item-wrapper.messenger').length);
    if (msgAfter === msgBefore) break;
    console.log(`消息滚动 ${i + 1}: ${msgBefore} → ${msgAfter}`);
    msgBefore = msgAfter;
  }
  console.log(`最终消息: ${msgBefore} 条`);

  // 3. 检查图片消息在DOM中的样子
  console.log('\n=== 图片消息检测 ===');
  const imgInfo = await talkFrame.evaluate(() => {
    const items = [];
    // Look for image-related elements in messages
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(el => {
      const imgs = el.querySelectorAll('img, [class*="image"], [class*="img"], [class*="picture"], [style*="background-image"]');
      const text = el.textContent?.substring(0, 80) || '';
      if (imgs.length > 0 || text.includes('[图片]') || text.includes('[image]')) {
        items.push({
          text: text.substring(0, 60),
          imgCount: imgs.length,
          imgTags: Array.from(imgs).map(i => i.tagName + (i.src ? ` src=${i.src.substring(0, 80)}` : '')),
        });
      }
    });
    return items.slice(0, 10);
  });
  console.log(`找到 ${imgInfo.length} 条含图片的消息`);
  imgInfo.forEach((item, i) => {
    console.log(`  [${i}] "${item.text}" 图片: ${item.imgCount} 个`);
    item.imgTags.forEach(t => console.log(`    ${t}`));
  });

  // 4. 尝试切换到"客户"模块
  console.log('\n=== 客户模块探查 ===');
  // Click the 客户 menu item in sidebar
  const custNav = await page.evaluate(() => {
    const items = document.querySelectorAll('.fixed-menu-item, a, li');
    for (const el of items) {
      if (el.textContent?.trim() === '客户') {
        el.click();
        return 'clicked 客户';
      }
    }
    return 'not found';
  });
  console.log(custNav);
  await new Promise(r => setTimeout(r, 3000));
  console.log('跳转后URL:', page.url());

  // Check if page content changed
  const pageText = await page.evaluate(() => document.body?.innerText?.substring(0, 3000) || '');
  console.log('页面内容:\n', pageText);

  await browser.close();
})().catch(err => { console.error(err.message); });

#!/usr/bin/env node

/**
 * 小满CRM — 全流程自动化
 *
 * 用法: node run-scrape.mjs
 * 前置条件:
 *   1. Chrome 已在端口 9222 开启 (node launch_okki2.js)
 *   2. 小满已登录并在 TM 消息页面
 */

import { chromium } from 'playwright';
import { writeFileSync, mkdirSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { classifyAll, getCategoryInfo } from './classifier.mjs';
import { generateReportDocx } from './reporter.mjs';
import { Packer } from 'docx';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..');
const CDP_URL = 'http://127.0.0.1:9222';

// ============================================================
// 连接小满
// ============================================================
async function connect() {
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  if (!page) throw new Error('未找到小满页面');
  const talkFrame = page.frames()[1];
  if (!talkFrame) throw new Error('未找到聊天 iframe');
  return { browser, page, talkFrame };
}

// ============================================================
// 提取会话列表
// ============================================================
async function getConversationList(frame) {
  return frame.evaluate(() => {
    return Array.from(document.querySelectorAll('.contact-item-container')).map(el => {
      const text = el.textContent || '';
      const nameEl = el.querySelector('.contact-right');
      const nameText = nameEl ? (nameEl.textContent || '').trim() : '';
      const nameMatch = nameText.match(/^(.+?)(?:\d{2,4}[-:\/])/);
      const name = nameMatch ? nameMatch[1].trim() : nameText.substring(0, 30).trim() || 'unknown';
      return {
        name,
        isUnread: text.includes('[未读]'),
        isSelected: el.classList.contains('selected'),
      };
    });
  });
}

// ============================================================
// 提取当前会话消息
// ============================================================
async function getCurrentMessages(frame) {
  return frame.evaluate(() => {
    const messages = [];
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(wrapper => {
      const isLeft = wrapper.classList.contains('item-left');
      const isRight = wrapper.classList.contains('item-right');
      const textEl = wrapper.querySelector('.session-rich-content.text');
      const cardEl = wrapper.querySelector('.session-rich-content.card');
      const securityEl = wrapper.querySelector('.session-security');

      if (!textEl && !cardEl) return;
      if (securityEl) return;

      const content = (textEl || cardEl).textContent.trim()
        .replace(/翻译中…反馈$/, '').replace(/由阿里翻译提供反馈$/, '')
        .replace(/阿里国际Marco大模型翻译反馈$/, '').replace(/由阿里翻译提供$/, '').trim();

      messages.push({
        side: isLeft ? 'received' : isRight ? 'sent' : 'system',
        content,
        isCard: !!cardEl,
      });
    });
    return messages;
  });
}

// ============================================================
// 点击会话
// ============================================================
async function clickConversation(frame, index) {
  const result = await frame.evaluate((idx) => {
    const containers = document.querySelectorAll('.contact-item-container');
    const target = containers[idx];
    if (!target) return null;
    target.scrollIntoView({ block: 'center' });
    target.click();
    return (target.textContent || '').trim().substring(0, 150);
  }, index);
  await new Promise(r => setTimeout(r, 2000));
  return result;
}

// ============================================================
// 提取单个会话详细消息（含重试）
// ============================================================
async function extractConversation(frame, conv, index) {
  const clicked = await clickConversation(frame, index);
  if (!clicked) return null;

  // Wait for messages to load
  for (let i = 0; i < 15; i++) {
    const hasContent = await frame.evaluate(() =>
      document.querySelectorAll('.session-rich-content.text, .session-rich-content.card').length > 0
    );
    if (hasContent) break;
    await new Promise(r => setTimeout(r, 500));
  }

  const messages = await getCurrentMessages(frame);
  return {
    name: conv.name,
    status: conv.isUnread ? 'unread' : 'read',
    messages,
    messageCount: messages.length,
  };
}

// ============================================================
// 滚动会话列表
// ============================================================
async function scrollToBottom(frame) {
  await frame.evaluate(() => {
    const container = document.querySelector('.seller-conversation-list') ||
      document.querySelector('.conversation-list-content');
    if (container) container.scrollTop = container.scrollHeight;
  });
  await new Promise(r => setTimeout(r, 500));
}

// ============================================================
// 主流程
// ============================================================
async function main() {
  console.log('╔══════════════════════════════════════╗');
  console.log('║   小满CRM 客户跟进管理系统            ║');
  console.log('║   数据抓取 → 分类 → 报告              ║');
  console.log('╚══════════════════════════════════════╝\n');

  // Step 1: 连接
  console.log('📡 连接小满...');
  const { browser, talkFrame } = await connect();
  console.log('✅ 连接成功\n');

  try {
    // Step 2: 获取会话列表
    console.log('📋 获取会话列表...');
    await scrollToBottom(talkFrame);
    await scrollToBottom(talkFrame);
    const conversations = await getConversationList(talkFrame);
    console.log(`   共 ${conversations.length} 个会话\n`);

    // Step 3: 提取详细消息（遍历前25个）
    const maxConv = conversations.length;
    const detailedConvs = [];
    const startTime = Date.now();

    for (let i = 0; i < maxConv; i++) {
      const conv = conversations[i];
      if (conv.name === 'Assistant Eva官方') continue;

      process.stdout.write(`   [${i + 1}/${maxConv}] ${conv.name}...`);

      const detail = await extractConversation(talkFrame, conv, i);
      if (detail) {
        detailedConvs.push(detail);
        process.stdout.write(` ${detail.messages.length} 条消息 ✅\n`);
      } else {
        process.stdout.write(' ⚠️ 跳过\n');
      }
    }

    const elapsed = ((Date.now() - startTime) / 1000).toFixed(0);
    console.log(`\n   抓取完成: ${detailedConvs.length} 个会话，耗时 ${elapsed}s\n`);

    // Step 4: 分类
    console.log('🏷️  分类...');
    const classified = classifyAll(detailedConvs);

    // 统计各分类
    const stats = {};
    for (const conv of classified) {
      const catId = conv.classification?.categoryId || 'other';
      stats[catId] = (stats[catId] || 0) + 1;
    }
    for (const [catId, count] of Object.entries(stats).sort()) {
      const info = getCategoryInfo(catId);
      if (info) {
        console.log(`   ${info.emoji} ${info.label}: ${count} 个`);
      }
    }
    console.log('');

    // Step 5: 生成 Word 报告
    console.log('📝 生成 Word 看板报告...');
    const doc = await generateReportDocx(classified, { generatedAt: new Date() });
    const timestamp = new Date().toISOString().replace(/[:]/g, '-').substring(0, 19);
    const reportPath = join(DATA_DIR, `看板报告_${timestamp}.docx`);
    const buffer = await Packer.toBuffer(doc);
    writeFileSync(reportPath, buffer);
    console.log(`   已保存: ${reportPath}`);

    // Step 6: 保存 JSON 原始数据
    const dataPath = join(DATA_DIR, `数据_${timestamp}.json`);
    writeFileSync(dataPath, JSON.stringify(classified, null, 2), 'utf-8');
    console.log(`   数据: ${dataPath}`);

    // Step 7: 输出摘要
    const p0Count = classified.filter(c => {
      const info = getCategoryInfo(c.classification?.categoryId);
      return info && info.priority === 'P0';
    }).length;

    console.log(`\n📊 摘要`);
    console.log(`   ${'─'.repeat(30)}`);
    console.log(`   总会话: ${classified.length}`);
    console.log(`   🔴 P0 紧急: ${p0Count} 个`);
    console.log(`   看板报告: 已生成`);
    console.log(`\n✅ 完成！`);

    return classified;
  } finally {
    await browser.close();
  }
}

main().catch(err => {
  console.error(`\n❌ 错误: ${err.message}`);
  process.exit(1);
});

