const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));

  // Navigate to TM from email page
  await page.evaluate(() => {
    const items = document.querySelectorAll('.fixed-menu-item, a, li');
    for (const el of items) {
      if (el.textContent?.trim() === '沟通') { el.click(); return; }
    }
  });
  await new Promise(r => setTimeout(r, 4000));

  const talkFrame = page.frames()[1];
  if (!talkFrame) { console.log('NO_TALK_FRAME'); return; }

  // Click first real conversation
  await talkFrame.evaluate(() => {
    const containers = document.querySelectorAll('.contact-item-container');
    for (const c of containers) {
      const text = c.textContent || '';
      if (!text.includes('Assistant') && !text.includes('Eva')) {
        c.click(); return;
      }
    }
  });
  await new Promise(r => setTimeout(r, 2500));

  // Look for file-related elements inside message wrappers
  const fileInfo = await talkFrame.evaluate(() => {
    const results = [];
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(w => {
      // Look for links
      const links = w.querySelectorAll('a[href]');
      links.forEach(a => {
        const href = a.href || '';
        const text = a.textContent?.trim() || '';
        if (href.includes('clouddisk') || href.includes('download') || href.includes('file') || href.includes('aliyun')) {
          results.push({ type: 'file_link', href: href.substring(0, 200), text: text.substring(0, 100), class: a.className?.substring(0, 50) });
        }
      });
      // Look for non-img media elements
      ['video','audio','embed','object','iframe'].forEach(tag => {
        w.querySelectorAll(tag).forEach(el => {
          results.push({ type: 'media_' + tag, src: (el.src || '').substring(0, 200) });
        });
      });
      // Look for elements with file-related class names
      w.querySelectorAll('[class*=\"file\"], [class*=\"attach\"], [class*=\"down\"]').forEach(el => {
        if (el.tagName !== 'IMG') {
          results.push({ type: 'file_class', class: el.className.substring(0, 80), text: el.textContent?.trim().substring(0, 80) || '' });
        }
      });
    });
    return results;
  });

  console.log('TM文件/附件检测:');
  if (fileInfo.length === 0) {
    console.log('  (无文件链接或附件元素)');
  } else {
    fileInfo.forEach((f, i) => console.log(\`  [\${i}] \${f.type}: \${JSON.stringify(f)}\`));  
  }

  // Also check what card messages look like - they might contain file info
  const cardInfo = await talkFrame.evaluate(() => {
    const cards = [];
    document.querySelectorAll('.session-rich-content.card').forEach(card => {
      cards.push({
        html: card.innerHTML.replace(/</g, '&lt;').substring(0, 1000),
        text: card.textContent?.trim().substring(0, 200),
      });
    });
    return cards.slice(0, 5);
  });
  console.log('\n卡片消息结构样例:');
  cardInfo.forEach((c, i) => console.log(\`  [\${i}] \${c.text}\n   HTML: \${c.html}\n\`));

  await browser.close();
})();
" 2>&1

