const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  const page = ctx.pages()[0];

  // Go to live-chat and inspect deeply
  await page.goto('https://crm.xiaoman.cn/talk/live-chat', { timeout: 8000, waitUntil: 'domcontentloaded' });
  await new Promise(r => setTimeout(r, 3000));

  // Check for shadow DOM or hidden containers
  const deepInspect = await page.evaluate(() => {
    const results = {};
    // Check all divs with significant content
    const allDivs = document.querySelectorAll('div[id], div[class]');
    const significant = [];
    allDivs.forEach(d => {
      const text = (d.textContent || '').trim();
      if (text.length > 50) {
        significant.push({
          id: d.id?.substring(0, 50),
          cls: (d.className || '').substring(0, 60),
          text: text.substring(0, 100),
        });
      }
    });
    results.significant = significant.slice(0, 20);

    // Check for #shadow-root
    results.shadowRoots = document.querySelectorAll('*').length;

    // Check localStorage/sessionStorage for TM-related data
    results.storageKeys = Object.keys(localStorage).filter(k => k.includes('talk') || k.includes('im') || k.includes('chat'));

    return results;
  });

  console.log('Deep inspect:', JSON.stringify(deepInspect, null, 2).substring(0, 3000));

  await browser.close();
})();
