const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  const page = ctx.pages()[0];

  // Try the main CRM page - maybe TM is embedded there
  await page.goto('https://crm.xiaoman.cn/', { timeout: 8000, waitUntil: 'domcontentloaded' });
  await new Promise(r => setTimeout(r, 3000));

  // Check all iframe sources
  const iframes = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('iframe')).map(f => ({
      src: f.src?.substring(0, 200),
      id: f.id,
      name: f.name,
    }));
  });
  console.log('IFrames on dashboard:', JSON.stringify(iframes));

  // Also check for any element with onclick that could open old TM
  const tmTriggers = await page.evaluate(() => {
    const results = [];
    document.querySelectorAll('[onclick], [data-*]').forEach(el => {
      const text = el.textContent?.trim()?.substring(0, 20);
      const onclick = el.getAttribute('onclick')?.substring(0, 150) || '';
      if (onclick.toLowerCase().includes('talk') || onclick.toLowerCase().includes('im') || onclick.toLowerCase().includes('chat')) {
        results.push({ text, onclick });
      }
    });
    return results;
  });
  console.log('TM triggers:', JSON.stringify(tmTriggers));

  // Try clicking the '沟通' sidebar link  
  await page.evaluate(() => {
    const links = document.querySelectorAll('a[href]');
    for (const a of links) {
      if (a.textContent?.trim() === '沟通') {
        // Check if we can open in new tab
        window.open(a.href, '_blank');
        return;
      }
    }
