/**
 * 提取当前会话消息中的文件链接（云盘/下载等）
 */
export async function extractFileUrls(frame) {
  return frame.evaluate(() => {
    const files = [];
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(wrapper => {
      // 卡消息中的链接
      wrapper.querySelectorAll('a').forEach(a => {
        const href = a.href || '';
        if (href.includes('clouddisk') || href.includes('download') || href.includes('aliyundoc')) {
          files.push({
            url: href,
            name: (a.textContent || '').trim() || (a.title || ''),
            type: 'clouddisk',
          });
        }
      });
      // 文件类元素的文本内容
      const cardText = wrapper.querySelector('.session-rich-content.card');
      if (cardText) {
        const text = cardText.textContent || '';
        // 常见的文件格式指示
        if (/\.(pdf|docx?|xlsx?|pptx?|zip|rar|jpg|png)\b/i.test(text) && !files.some(f => f.text === text)) {
          files.push({ url: '', name: text.substring(0, 100), type: 'card_reference' });
        }
      }
    });
    return files;
  });
}

