#!/usr/bin/env node

/**
 * 小满CRM — 邮件抓取模块
 *
 * 抓取 leod.chen@yiyangxiaoxingxing.com 邮箱的邮件
 * 匹配 TM 客户名 → 提取正文 + 图片 + 附件
 *
 * 用法: node mail-scraper.mjs
 * 前置: Chrome 9222 已开启，小满已登录
 */

import { chromium } from 'playwright';
import { writeFileSync, mkdirSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..');
const MAIL_IMAGES_DIR = join(DATA_DIR, 'images', '__mail__');
const CDP_URL = 'http://127.0.0.1:9222';
const TARGET_MAIL_ID = '48725145'; // leod.chen@yiyangxiaoxingxing.com

// ============================================================
// 连接 + 导航到目标邮箱
// ============================================================
async function connectToMail() {
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));

  // 导航到邮件模块
  if (!page.url().includes('/mail/')) {
    await page.evaluate(() => {
      for (const el of document.querySelectorAll('.fixed-menu-item')) {
        if (el.textContent?.trim() === '邮件') { el.click(); return; }
      }
    });
    await new Promise(r => setTimeout(r, 5000));
  }

  // 切换到 leod.chen 邮箱
  if (!page.url().includes(`user_mail_id=${TARGET_MAIL_ID}`)) {
    await page.evaluate(() => {
      for (const el of document.querySelectorAll('.mail-sidebar-menu-item')) {
        if ((el.textContent || '').includes('leod.chen')) { el.click(); return; }
      }
    });
    await new Promise(r => setTimeout(r, 3000));
  }

  return { browser, ctx, page };
}

// ============================================================
// 获取邮件列表元数据
// ============================================================
async function getMailList(page) {
  return page.evaluate(() => {
    const items = document.querySelectorAll('.plain-list-item');
    return Array.from(items).map(item => {
      const text = item.textContent || '';
      const senderEl = item.querySelector('.mail-from, [class*=\"from\"]');
      const subjectEl = item.querySelector('.subject');
      const timeEl = item.querySelector('.time');
      const sender = senderEl ? senderEl.textContent.trim() : text.split('\n')[0]?.trim() || '';
      const subject = subjectEl ? subjectEl.textContent.trim() : '';
      const time = timeEl ? timeEl.textContent.trim() : '';
      return { sender, subject, time, fullText: text.substring(0, 300) };
    });
  });
}

// ============================================================
// 解析邮件列表项的详细信息
// ============================================================
async function parseMailList(page) {
  return page.evaluate(() => {
    const items = document.querySelectorAll('.plain-list-item');
    return Array.from(items).map(item => {
      // Walk text nodes to get structured fields
      const walker = document.createTreeWalker(item, NodeFilter.SHOW_TEXT, null);
      const textNodes = [];
      while (walker.nextNode()) {
        const t = walker.currentNode.textContent.trim();
        if (!t) continue;
        const parent = walker.currentNode.parentElement;
        const cls = parent ? (typeof parent.className === 'string' ? parent.className : '') : '';
        textNodes.push({ text: t, class: cls });
      }

      const senderName = textNodes[0]?.text || '';
      const senderEmail = textNodes[1]?.text || '';
      const subject = textNodes.find(n => n.class.includes('subject'))?.text || '';
      const preview = textNodes.find(n => n.class === 'ellipsis' && n.text !== subject)?.text || '';
      const time = textNodes.find(n => n.class.includes('time'))?.text || '';
      const hasPin = textNodes.some(n => n.class.includes('pin'));
      const hasPending = textNodes.some(n => n.class.includes('pending'));

      return { senderName, senderEmail, subject, preview, time, hasPin, hasPending };
    });
  });
}

// ============================================================
// 滚动邮件列表到底部（触发懒加载）
// ============================================================
async function scrollMailList(page) {
  await page.evaluate(() => {
    const scroller = document.querySelector('.mail-list-scroll-content');
    if (scroller) scroller.scrollTop = scroller.scrollHeight;
  });
  await new Promise(r => setTimeout(r, 500));
}

// ============================================================
// 翻到下一页
// ============================================================
async function goNextPage(page) {
  const clicked = await page.evaluate(() => {
    const btn = document.querySelector('.mail-paging-btn.right-btn');
    if (btn && !btn.classList.contains('disabled')) {
      btn.click();
      return true;
    }
    return false;
  });
  if (clicked) await new Promise(r => setTimeout(r, 3000));
  return clicked;
}

// ============================================================
// 获取当前页数信息
// ============================================================
async function getPageInfo(page) {
  return page.evaluate(() => {
    const totalEl = document.querySelector('.total-count');
    const unitEl = document.querySelector('.page-unit');
    const total = totalEl ? totalEl.textContent.trim() : '';
    const pageInfo = unitEl ? unitEl.textContent.trim() : '';
    return { total, pageInfo };
  });
}

// ============================================================
// 点击邮件打开详情
// ============================================================
async function clickMail(page, index) {
  const result = await page.evaluate((idx) => {
    const items = document.querySelectorAll('.plain-list-item');
    const target = items[idx];
    if (!target) return false;
    const wrapper = target.querySelector('.mail-item-container');
    if (wrapper) {
      wrapper.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true }));
      return true;
    }
    return false;
  }, index);
  await new Promise(r => setTimeout(r, 3000));
  return result;
}

// ============================================================
// 提取邮件正文（从 iframe 中）
// ============================================================
async function getMailDetail(page) {
  return page.evaluate(() => {
    const rightPane = document.querySelector('.mm-split-pane__right');
    if (!rightPane) return null;

    // Header: sender, recipient, subject
    const text = rightPane.innerText || '';

    // Email body from iframe
    const iframe = rightPane.querySelector('iframe');
    let bodyText = '';
    let bodyHTML = '';
    let images = [];
    let attachments = [];

    if (iframe) {
      try {
        const doc = iframe.contentDocument || iframe.contentWindow.document;
        if (doc && doc.body) {
          bodyText = doc.body.innerText || '';
          bodyHTML = doc.body.innerHTML || '';

          // Extract images from iframe
          doc.querySelectorAll('img').forEach(img => {
            if (img.src && img.src.startsWith('http')) {
              images.push({
                src: img.src,
                alt: img.alt || '',
                width: img.width,
                height: img.height,
              });
            }
          });

          // Extract attachment links from iframe
          doc.querySelectorAll('a[href]').forEach(a => {
            const href = a.href || '';
            if (href.includes('download') || href.includes('attach') || href.includes('aliyundoc')) {
              attachments.push({ url: href, text: a.textContent.trim() });
            }
          });
        }
      } catch (e) {
        bodyText = '(iframe access blocked)';
      }
    }

    // Find attachment elements outside iframe
    const attachElems = rightPane.querySelectorAll('[class*=\"attachment\"], [class*=\"attach\"]');
    attachElems.forEach(el => {
      const link = el.querySelector('a');
      if (link) {
        attachments.push({ url: link.href || '', text: link.textContent.trim() });
      }
    });

    return { text, bodyText, bodyHTML: bodyHTML.substring(0, 2000), images, attachments };
  });
}

// ============================================================
// 保存邮件图片
// ============================================================
async function saveMailImage(page, url, savePath) {
  const response = await page.goto(url, { waitUntil: 'load', timeout: 20000 });
  if (!response.ok()) throw new Error(`HTTP ${response.status()}`);
  const buffer = await response.body();
  writeFileSync(savePath, buffer);
  return buffer.length;
}

// ============================================================
// 主流程
// ============================================================
async function main() {
  console.log('╔══════════════════════════════════════╗');
  console.log('║   小满CRM 邮件抓取模块               ║');
  console.log('║   leod.chen@yiyangxiaoxingxing.com    ║');
  console.log('╚══════════════════════════════════════╝\n');

  // Connect
  console.log('📡 连接小满邮件...');
  const { browser, ctx, page } = await connectToMail();
  console.log('✅ 已进入目标邮箱\n');

  // 确保图片目录
  if (!existsSync(MAIL_IMAGES_DIR)) mkdirSync(MAIL_IMAGES_DIR, { recursive: true });

  try {
    // Extract all email metadata from all pages
    console.log('📋 扫描邮件列表...');
    const info = await getPageInfo(page);
    console.log(`   ${info.total} / ${info.pageInfo}\n`);

