import { chromium } from 'playwright';
import { writeFileSync, mkdirSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { createHash } from 'crypto';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..');
const MAIL_IMG_DIR = join(DATA_DIR, 'images', '__mail__');
if (!existsSync(MAIL_IMG_DIR)) mkdirSync(MAIL_IMG_DIR, { recursive: true });

const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
const ctx = browser.contexts()[0];
let page = ctx.pages().find(p => p.url().includes('xiaoman'));

// Navigate to sent folder
if (!page.url().includes('/mail/')) {
  await page.evaluate(() => {
    for (const el of document.querySelectorAll('.fixed-menu-item')) {
      if (el.textContent?.trim() === '邮件') { el.click(); return; }
    }
  });
  await new Promise(r => setTimeout(r, 5000));
}

// Click 发件箱 title
await page.evaluate(() => {
  for (const t of document.querySelectorAll('.okki-menu-submenu-title')) {
    if ((t.textContent || '').includes('发件箱')) { t.click(); return; }
  }
});
await new Promise(r => setTimeout(r, 2000));

// Click leod.chen under 发件箱
await page.evaluate(() => {
  const submenus = document.querySelectorAll('.okki-menu-submenu');
  for (const sm of submenus) {
    const title = sm.querySelector('.okki-menu-submenu-title');
    if (title && (title.textContent || '').includes('发件箱')) {
      for (const item of sm.querySelectorAll('.mail-sidebar-menu-item')) {
        if ((item.textContent || '').includes('leod.chen')) { item.click(); return; }
      }
    }
  }
});
await new Promise(r => setTimeout(r, 3000));

console.log('URL:', page.url().substring(0, 200));

// Parse sent mail list
const sentMails = await page.evaluate(() => {
  const items = document.querySelectorAll('.plain-list-item');
  return Array.from(items).map((item, idx) => {
    const walker = document.createTreeWalker(item, NodeFilter.SHOW_TEXT, null);
    const nodes = [];
    while (walker.nextNode()) {
      const t = walker.currentNode.textContent.trim();
      if (!t) continue;
      const p = walker.currentNode.parentElement;
      const cls = p ? (typeof p.className === 'string' ? p.className : '') : '';
      nodes.push({ t, cls });
    }
    return {
      idx,
      senderName: nodes[0]?.t || '',
      senderEmail: nodes[1]?.t || '',
      subject: nodes.find(n => n.cls.includes('subject'))?.t || '',
      preview: nodes.filter(n => n.cls === 'ellipsis').map(n => n.t).join(' '),
      time: nodes.find(n => n.cls.includes('time'))?.t || '',
    };
  });
});
console.log('\n=== Sent emails ===');
sentMails.forEach((m, i) => {
  console.log('['+i+']', m.subject);
  console.log('    To:', m.senderName, '<'+m.senderEmail+'>');
  console.log('    Time:', m.time);
  console.log('    Preview:', (m.preview||'').substring(0, 100));
});

// Extract detail for each
const saveMailImages = async (images) => {
  const saved = [];
  for (const img of images) {
    try {
      const ext = img.src.match(/\.(jpe?g|png|gif|webp)(?:[?#]|$)/i)?.[1] || 'jpg';
      const hash = createHash('md5').update(img.src).digest('hex').substring(0, 10);
      const filePath = join(MAIL_IMG_DIR, Date.now()+'_'+hash+'.'+ext);
      const p = await ctx.newPage();
      try {
        const r = await p.goto(img.src, { waitUntil: 'load', timeout: 15000 });
        if (r && r.ok()) {
          const buf = await r.body();
          writeFileSync(filePath, buf);
          saved.push({ url: img.src, filePath, size: buf.length });
        }
      } finally { await p.close(); }
    } catch {}
  }
  return saved;
};

const detailed = [];
for (const mail of sentMails) {
  process.stdout.write('\n📧 \"'+mail.subject.substring(0, 50)+'\"...');
  const ok = await page.evaluate((idx) => {
    const items = document.querySelectorAll('.plain-list-item');
    const t = items[idx]; if (!t) return false;
    const w = t.querySelector('.mail-item-container'); if (!w) return false;
    w.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true }));
    return true;
  }, mail.idx);
  if (!ok) { console.log(' ❌'); continue; }
  await new Promise(r => setTimeout(r, 3000));

  const detail = await page.evaluate(() => {
    const iframe = document.querySelector('.mm-split-pane__right iframe');
    if (!iframe) return { bodyText: '', images: [] };
    try {
      const doc = iframe.contentDocument || iframe.contentWindow.document;
      if (!doc || !doc.body) return { bodyText: '', images: [] };
      return {
        bodyText: (doc.body.innerText || '').substring(0, 5000),
        images: Array.from(doc.querySelectorAll('img'))
          .filter(img => img.src && img.src.startsWith('http'))
          .map(img => ({ src: img.src, alt: img.alt || '' })),
      };
    } catch { return { bodyText: '', images: [] }; }
  });

  const savedImages = await saveMailImages(detail.images);
  detailed.push({ ...mail, bodyText: detail.bodyText, images: savedImages });
  process.stdout.write(' ✅ ('+savedImages.length+'图)\n');
}

// Save
const timestamp = new Date().toISOString().replace(/[:]/g, '-').substring(0, 19);
const outputPath = join(DATA_DIR, '发件数据_'+timestamp+'.json');
writeFileSync(outputPath, JSON.stringify(detailed, null, 2), 'utf-8');
console.log('\n✅ 发件箱抓取完成');
console.log('   已保存:', outputPath);

await browser.close();
" 2>&1

