// ============================================================
const COLORS = {
  primary: '1A237E',     // 深蓝（标题）
  secondary: '283593',   // 中蓝（子标题）
  accent: '5C6BC0',      // 浅蓝（强调）
  text: '333333',         // 正文
  gray: '888888',         // 辅助文字
  light: 'BBBBBB',        // 轻灰
